queries.sparql:
PREFIX : <http://ambrosia.example.org/traffic#>
PREFIX p: <http://ambrosia.example.org/traffic/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasSafety_Features ?child ; p:hasCars ?parent . } GROUP BY ?child }
  ?child p:name ?name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Cars } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/traffic#>
PREFIX p: <http://ambrosia.example.org/traffic/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?make ?name WHERE {
  ?cars_safety_features a :Cars_Safety_Features .
  ?safety_features a :Safety_Features .
  ?cars_safety_features p:hasSafety_Features ?safety_features .
  ?cars a :Cars .
  ?cars_safety_features p:hasCars ?cars .
  ?cars p:make ?make .
  ?safety_features p:name ?name .
} }
  collective: { SELECT ?name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasSafety_Features ?child ; p:hasCars ?parent . } GROUP BY ?child }
  ?child p:name ?name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Cars } }
  FILTER(?nf = ?total)
} }
}
